{
  "name": "El Neguev - Comida Criolla",
  "description": "Aplicación oficial del restaurante El Neguev para pedidos del plato del día, gestión administrativa y seguimiento de repartos en tiempo real.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PREPARING = 'PREPARING',
  IN_TRANSIT = 'IN_TRANSIT',
  DELIVERED = 'DELIVERED',
  CANCELLED = 'CANCELLED'
}

export interface Dish {
  id: string;
  name: string;
  description: string;
  price: number;
  imageUrl: string;
  available: boolean;
}

export interface Order {
  id: string;
  customerName: string;
  address: string;
  phone: string;
  items: { dishId: string; quantity: number; name: string; price: number }[];
  total: number;
  status: OrderStatus;
  deliveryAssignedTo?: string;
  createdAt: number;
}

export interface DeliveryPerson {
  id: string;
  name: string;
  active: boolean;
}

export type AppRole = 'CLIENT' | 'ADMIN' | 'DELIVERY';

import { Order, OrderStatus, Dish, DeliveryPerson } from '../types';

const KEYS = {
  ORDERS: 'el_neguev_orders',
  MENU: 'el_neguev_menu',
  DELIVERY_PEOPLE: 'el_neguev_delivery_people'
};

const DEFAULT_MENU: Dish[] = [
  {
    id: '1',
    name: 'La Bandera Dominicana',
    description: 'Arroz blanco, habichuelas rojas guisadas, carne de pollo o res, y ensalada verde.',
    price: 350,
    imageUrl: 'https://picsum.photos/seed/bandera/800/600',
    available: true
  },
  {
    id: '2',
    name: 'Sancocho Tradicional',
    description: 'El clásico caldo dominicano con 7 carnes, víveres y aguacate.',
    price: 450,
    imageUrl: 'https://picsum.photos/seed/sancocho/800/600',
    available: true
  }
];

const DEFAULT_DELIVERY: DeliveryPerson[] = [
  { id: 'd1', name: 'Juan Repartidor', active: true },
  { id: 'd2', name: 'Pedro Veloz', active: true }
];

export const StorageService = {
  getOrders: (): Order[] => {
    const data = localStorage.getItem(KEYS.ORDERS);
    return data ? JSON.parse(data) : [];
  },

  saveOrder: (order: Order) => {
    const orders = StorageService.getOrders();
    orders.push(order);
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(orders));
  },

  updateOrderStatus: (orderId: string, status: OrderStatus) => {
    const orders = StorageService.getOrders();
    const updated = orders.map(o => o.id === orderId ? { ...o, status } : o);
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(updated));
  },

  assignDelivery: (orderId: string, deliveryId: string) => {
    const orders = StorageService.getOrders();
    const updated = orders.map(o => o.id === orderId ? { 
      ...o, 
      deliveryAssignedTo: deliveryId,
      status: OrderStatus.PREPARING 
    } : o);
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(updated));
  },

  getMenu: (): Dish[] => {
    const data = localStorage.getItem(KEYS.MENU);
    return data ? JSON.parse(data) : DEFAULT_MENU;
  },

  saveMenu: (menu: Dish[]) => {
    localStorage.setItem(KEYS.MENU, JSON.stringify(menu));
  },

  getDeliveryPeople: (): DeliveryPerson[] => {
    const data = localStorage.getItem(KEYS.DELIVERY_PEOPLE);
    return data ? JSON.parse(data) : DEFAULT_DELIVERY;
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const GeminiService = {
  suggestDailyMenu: async (theme: string = "Tradicional") => {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Eres un chef experto en comida criolla Dominicana del restaurante "El Neguev". 
        Sugiere 3 platos del día con el tema: ${theme}. 
        Para cada plato dame: Nombre, una descripción deliciosa y un precio sugerido en Pesos Dominicanos (DOP).`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                price: { type: Type.NUMBER }
              },
              required: ["name", "description", "price"]
            }
          }
        }
      });
      return JSON.parse(response.text);
    } catch (error) {
      console.error("Error generating menu:", error);
      return null;
    }
  }
};

