import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { Dish, Order, OrderStatus } from '../types';

const CustomerView: React.FC = () => {
  const [menu, setMenu] = useState<Dish[]>([]);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);
  const [formData, setFormData] = useState({ name: '', address: '', phone: '' });
  const [isOrdering, setIsOrdering] = useState(false);
  const [selectedDish, setSelectedDish] = useState<Dish | null>(null);

  useEffect(() => {
    setMenu(StorageService.getMenu());
    // Check for existing active orders in session to simulate live tracking
    const orders = StorageService.getOrders();
    const lastOrder = orders.find(o => o.status !== OrderStatus.DELIVERED);
    if (lastOrder) setActiveOrder(lastOrder);

    // Refresh order status every 5 seconds
    const interval = setInterval(() => {
      const updatedOrders = StorageService.getOrders();
      if (lastOrder) {
        const refreshed = updatedOrders.find(o => o.id === lastOrder.id);
        if (refreshed) setActiveOrder(refreshed);
      }
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDish) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      customerName: formData.name,
      address: formData.address,
      phone: formData.phone,
      items: [{
        dishId: selectedDish.id,
        name: selectedDish.name,
        quantity: 1,
        price: selectedDish.price
      }],
      total: selectedDish.price,
      status: OrderStatus.PENDING,
      createdAt: Date.now()
    };

    StorageService.saveOrder(newOrder);
    setActiveOrder(newOrder);
    setIsOrdering(false);
    setSelectedDish(null);
    alert('¡Pedido realizado con éxito! Sigue el estado en vivo.');
  };

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-yellow-100 text-yellow-800';
      case OrderStatus.PREPARING: return 'bg-blue-100 text-blue-800';
      case OrderStatus.IN_TRANSIT: return 'bg-purple-100 text-purple-800';
      case OrderStatus.DELIVERED: return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusLabel = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'Esperando Aprobación';
      case OrderStatus.PREPARING: return 'En la Cocina / Preparando';
      case OrderStatus.IN_TRANSIT: return 'En Camino';
      case OrderStatus.DELIVERED: return 'Entregado';
      default: return 'Desconocido';
    }
  };

  if (activeOrder && activeOrder.status !== OrderStatus.DELIVERED) {
    return (
      <div className="max-w-2xl mx-auto py-8">
        <h2 className="text-3xl font-bold mb-6 text-center text-orange-700">Tu Pedido Live 🛵</h2>
        <div className="bg-white rounded-2xl shadow-xl p-8 border border-orange-100">
          <div className="flex justify-between items-center mb-8">
            <div>
              <p className="text-stone-500 text-sm uppercase font-bold tracking-widest">Estado Actual</p>
              <p className={`mt-2 px-4 py-1 rounded-full text-lg font-bold inline-block ${getStatusColor(activeOrder.status)}`}>
                {getStatusLabel(activeOrder.status)}
              </p>
            </div>
            <div className="text-right">
              <p className="text-stone-500 text-sm">Orden ID</p>
              <p className="font-mono text-stone-800">#{activeOrder.id.toUpperCase()}</p>
            </div>
          </div>

          <div className="space-y-6 relative before:content-[''] before:absolute before:left-[19px] before:top-2 before:bottom-2 before:w-1 before:bg-orange-100">
            <div className="flex items-start relative z-10">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${activeOrder.status !== OrderStatus.CANCELLED ? 'bg-orange-600' : 'bg-stone-300'}`}>
                <i className="fa-solid fa-receipt text-white text-xs"></i>
              </div>
              <div className="ml-4">
                <h4 className="font-bold">Recibido</h4>
                <p className="text-sm text-stone-500">Estamos revisando tu pedido</p>
              </div>
            </div>
            <div className="flex items-start relative z-10">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.PREPARING, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                <i className="fa-solid fa-fire-burner text-white text-xs"></i>
              </div>
              <div className="ml-4">
                <h4 className="font-bold">Preparando</h4>
                <p className="text-sm text-stone-500">Nuestros chefs están manos a la obra</p>
              </div>
            </div>
            <div className="flex items-start relative z-10">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                <i className="fa-solid fa-motorcycle text-white text-xs"></i>
              </div>
              <div className="ml-4">
                <h4 className="font-bold">En Camino</h4>
                <p className="text-sm text-stone-500">¡Tu comida está viajando hacia ti!</p>
              </div>
            </div>
            <div className="flex items-start relative z-10">
              <div className={`w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${activeOrder.status === OrderStatus.DELIVERED ? 'bg-green-600' : 'bg-stone-200'}`}>
                <i className="fa-solid fa-check text-white text-xs"></i>
              </div>
              <div className="ml-4">
                <h4 className="font-bold">Entregado</h4>
                <p className="text-sm text-stone-500">¡Buen provecho!</p>
              </div>
            </div>
          </div>

          <div className="mt-10 pt-6 border-t border-stone-100">
            <h5 className="font-bold mb-2">Detalles del Envío</h5>
            <p className="text-stone-600 italic">"{activeOrder.address}"</p>
            <p className="text-stone-600 mt-1">Para: {activeOrder.customerName}</p>
          </div>

          <button 
            onClick={() => setActiveOrder(null)}
            className="w-full mt-8 bg-stone-100 text-stone-600 py-3 rounded-xl font-bold hover:bg-stone-200 transition"
          >
            Volver al Menú
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-12">
      <section className="text-center bg-orange-50 py-12 px-4 rounded-3xl">
        <h1 className="text-4xl md:text-5xl font-black text-orange-800 mb-4 uppercase">El Neguev</h1>
        <p className="text-lg text-orange-700 max-w-2xl mx-auto font-medium">
          El verdadero sabor de la cocina criolla Dominicana en tu puerta.
        </p>
        <div className="mt-8 flex justify-center space-x-4">
            <span className="bg-white px-4 py-2 rounded-full shadow-sm text-orange-600 font-bold border border-orange-100">🇩🇴 100% Auténtico</span>
            <span className="bg-white px-4 py-2 rounded-full shadow-sm text-orange-600 font-bold border border-orange-100">🚀 Entrega Rápida</span>
        </div>
      </section>

      <section>
        <div className="flex items-center justify-between mb-8">
          <h2 className="text-3xl font-bold border-l-8 border-orange-600 pl-4">Platos del Día</h2>
          <span className="bg-orange-100 text-orange-800 px-4 py-1 rounded-full text-sm font-bold animate-pulse">
            MENÚ HOY: {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
          </span>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {menu.filter(d => d.available).map(dish => (
            <div key={dish.id} className="bg-white rounded-3xl shadow-sm border border-stone-100 overflow-hidden group hover:shadow-xl transition-all duration-300">
              <div className="h-56 relative overflow-hidden">
                <img src={dish.imageUrl} alt={dish.name} className="w-full h-full object-cover group-hover:scale-105 transition duration-500" />
                <div className="absolute top-4 right-4 bg-orange-600 text-white px-4 py-1 rounded-full font-bold shadow-lg">
                  RD$ {dish.price}
                </div>
              </div>
              <div className="p-6">
                <h3 className="text-xl font-bold mb-2 group-hover:text-orange-600 transition">{dish.name}</h3>
                <p className="text-stone-600 text-sm mb-6 leading-relaxed">
                  {dish.description}
                </p>
                <button 
                  onClick={() => {
                    setSelectedDish(dish);
                    setIsOrdering(true);
                  }}
                  className="w-full bg-orange-600 text-white py-3 rounded-2xl font-bold hover:bg-orange-700 shadow-md active:scale-95 transition"
                >
                  Ordenar Ahora
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {isOrdering && selectedDish && (
        <div className="fixed inset-0 bg-stone-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg p-8 transform animate-in fade-in zoom-in duration-300">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-bold">Confirma tu Orden</h3>
              <button onClick={() => setIsOrdering(false)} className="text-stone-400 hover:text-stone-600">
                <i className="fa-solid fa-xmark text-2xl"></i>
              </button>
            </div>

            <div className="bg-orange-50 p-4 rounded-2xl mb-6 flex items-center space-x-4">
              <img src={selectedDish.imageUrl} className="w-16 h-16 rounded-xl object-cover" />
              <div>
                <p className="font-bold">{selectedDish.name}</p>
                <p className="text-orange-600 font-bold">RD$ {selectedDish.price}</p>
              </div>
            </div>

            <form onSubmit={handleOrder} className="space-y-4">
              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1">Nombre Completo</label>
                <input 
                  required
                  type="text" 
                  className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-orange-500 outline-none" 
                  placeholder="Ej. Maria Martinez"
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1">Dirección de Envío</label>
                <input 
                  required
                  type="text" 
                  className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-orange-500 outline-none" 
                  placeholder="Calle, Número, Sector"
                  value={formData.address}
                  onChange={(e) => setFormData({...formData, address: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-stone-700 mb-1">Teléfono</label>
                <input 
                  required
                  type="tel" 
                  className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-orange-500 outline-none" 
                  placeholder="809-XXX-XXXX"
                  value={formData.phone}
                  onChange={(e) => setFormData({...formData, phone: e.target.value})}
                />
              </div>
              <button 
                type="submit"
                className="w-full bg-orange-600 text-white py-4 rounded-2xl font-bold hover:bg-orange-700 transition mt-4"
              >
                Confirmar y Pedir
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomerView;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storageService';
import { GeminiService } from '../services/geminiService';
import { Dish, Order, DeliveryPerson, OrderStatus } from '../types';

const AdminView: React.FC = () => {
  const [menu, setMenu] = useState<Dish[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [deliveryPeople, setDeliveryPeople] = useState<DeliveryPerson[]>([]);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiTheme, setAiTheme] = useState('Criollo Tradicional');

  useEffect(() => {
    refreshData();
    const interval = setInterval(refreshData, 10000);
    return () => clearInterval(interval);
  }, []);

  const refreshData = () => {
    setMenu(StorageService.getMenu());
    setOrders(StorageService.getOrders().sort((a, b) => b.createdAt - a.createdAt));
    setDeliveryPeople(StorageService.getDeliveryPeople());
  };

  const handleAiSuggest = async () => {
    setIsAiLoading(true);
    const suggestions = await GeminiService.suggestDailyMenu(aiTheme);
    if (suggestions) {
      const newMenu: Dish[] = suggestions.map((s: any, idx: number) => ({
        id: `ai-${Date.now()}-${idx}`,
        name: s.name,
        description: s.description,
        price: s.price,
        imageUrl: `https://picsum.photos/seed/${s.name}/800/600`,
        available: true
      }));
      setMenu(newMenu);
      StorageService.saveMenu(newMenu);
      alert('¡Menú actualizado con sugerencias de IA!');
    }
    setIsAiLoading(false);
  };

  const handleAssign = (orderId: string, deliveryId: string) => {
    StorageService.assignDelivery(orderId, deliveryId);
    refreshData();
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      {/* Menu Management Section */}
      <section className="lg:col-span-1 space-y-6">
        <div className="bg-white rounded-3xl shadow-sm border border-stone-200 p-6">
          <h3 className="text-xl font-bold mb-4 flex items-center">
            <i className="fa-solid fa-wand-magic-sparkles text-orange-500 mr-2"></i>
            Asistente de Menú IA
          </h3>
          <p className="text-stone-500 text-sm mb-4">Genera un menú del día creativo usando Inteligencia Artificial.</p>
          <div className="space-y-3">
            <input 
              type="text" 
              className="w-full px-4 py-2 rounded-xl border border-stone-200 outline-none focus:ring-2 focus:ring-orange-500" 
              placeholder="Ej: Mariscos, San Valentín..."
              value={aiTheme}
              onChange={(e) => setAiTheme(e.target.value)}
            />
            <button 
              onClick={handleAiSuggest}
              disabled={isAiLoading}
              className="w-full bg-orange-600 text-white py-3 rounded-xl font-bold hover:bg-orange-700 disabled:bg-orange-300 transition flex items-center justify-center"
            >
              {isAiLoading ? (
                <>
                  <i className="fa-solid fa-spinner animate-spin mr-2"></i>
                  Cocinando Ideas...
                </>
              ) : 'Generar Menú'}
            </button>
          </div>
        </div>

        <div className="bg-white rounded-3xl shadow-sm border border-stone-200 p-6">
          <h3 className="text-xl font-bold mb-4">Menú Actual</h3>
          <div className="space-y-4">
            {menu.map(item => (
              <div key={item.id} className="flex items-center space-x-3 p-3 bg-stone-50 rounded-2xl border border-stone-100">
                <img src={item.imageUrl} className="w-12 h-12 rounded-lg object-cover" />
                <div className="flex-grow">
                  <p className="font-bold text-sm">{item.name}</p>
                  <p className="text-xs text-orange-600 font-bold">RD$ {item.price}</p>
                </div>
                <div className={`w-3 h-3 rounded-full ${item.available ? 'bg-green-500' : 'bg-red-500'}`}></div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Orders Management Section */}
      <section className="lg:col-span-2 space-y-6">
        <div className="bg-white rounded-3xl shadow-sm border border-stone-200 p-6 overflow-hidden">
          <h3 className="text-2xl font-bold mb-6 flex items-center justify-between">
            Gestión de Órdenes
            <span className="text-xs bg-stone-100 text-stone-500 px-3 py-1 rounded-full uppercase tracking-widest font-bold">
              Total: {orders.length}
            </span>
          </h3>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="border-b border-stone-100 text-stone-400 text-xs uppercase font-bold">
                  <th className="pb-4 pr-4">Orden</th>
                  <th className="pb-4 pr-4">Cliente / Dirección</th>
                  <th className="pb-4 pr-4">Total</th>
                  <th className="pb-4 pr-4">Estado</th>
                  <th className="pb-4">Asignar Delivery</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-stone-50">
                {orders.map(order => (
                  <tr key={order.id} className="hover:bg-stone-50/50 transition">
                    <td className="py-4 pr-4 align-top">
                      <p className="font-mono text-xs font-bold text-stone-400">#{order.id.toUpperCase()}</p>
                    </td>
                    <td className="py-4 pr-4 align-top">
                      <p className="font-bold text-sm">{order.customerName}</p>
                      <p className="text-xs text-stone-500 italic max-w-xs">{order.address}</p>
                    </td>
                    <td className="py-4 pr-4 align-top">
                      <p className="font-bold text-sm text-orange-600">RD$ {order.total}</p>
                    </td>
                    <td className="py-4 pr-4 align-top">
                      <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase ${
                        order.status === OrderStatus.PENDING ? 'bg-yellow-100 text-yellow-800' :
                        order.status === OrderStatus.PREPARING ? 'bg-blue-100 text-blue-800' :
                        order.status === OrderStatus.IN_TRANSIT ? 'bg-purple-100 text-purple-800' :
                        'bg-green-100 text-green-800'
                      }`}>
                        {order.status}
                      </span>
                    </td>
                    <td className="py-4 align-top">
                      {order.status === OrderStatus.PENDING ? (
                        <select 
                          className="text-xs bg-white border border-stone-200 rounded-lg p-1 outline-none focus:ring-2 focus:ring-orange-500"
                          onChange={(e) => handleAssign(order.orderId || order.id, e.target.value)}
                          defaultValue=""
                        >
                          <option value="" disabled>Seleccionar...</option>
                          {deliveryPeople.map(d => (
                            <option key={d.id} value={d.id}>{d.name}</option>
                          ))}
                        </select>
                      ) : (
                        <p className="text-xs text-stone-400 italic">
                          {deliveryPeople.find(d => d.id === order.deliveryAssignedTo)?.name || 'Asignado'}
                        </p>
                      )}
                    </td>
                  </tr>
                ))}
                {orders.length === 0 && (
                  <tr>
                    <td colSpan={5} className="py-12 text-center text-stone-400 italic">
                      No hay órdenes pendientes hoy.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </section>
    </div>
  );
};

