declare const L: any; // Leaflet global

const CustomerView: React.FC = () => {
  const [menu, setMenu] = useState<Dish[]>([]);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);
  const [formData, setFormData] = useState({ name: '', address: '', phone: '' });
  const [isOrdering, setIsOrdering] = useState(false);
  const [selectedDish, setSelectedDish] = useState<Dish | null>(null);

  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);

  useEffect(() => {
    setMenu(StorageService.getMenu());
    const orders = StorageService.getOrders();
    const lastOrder = orders.find(o => o.status !== OrderStatus.DELIVERED && o.status !== OrderStatus.CANCELLED);
    if (lastOrder) setActiveOrder(lastOrder);

    const interval = setInterval(() => {
      const updatedOrders = StorageService.getOrders();
      const currentOrderId = activeOrder?.id || lastOrder?.id;
      if (currentOrderId) {
        const refreshed = updatedOrders.find(o => o.id === currentOrderId);
        if (refreshed) {
          setActiveOrder(refreshed);
        }
      }
    }, 3000);

    return () => clearInterval(interval);
  }, [activeOrder?.id]);

  // Handle Map Logic
  useEffect(() => {
    if (activeOrder?.status === OrderStatus.IN_TRANSIT && activeOrder.deliveryLocation && mapContainerRef.current) {
      const loc = activeOrder.deliveryLocation;

      if (!mapRef.current) {
        mapRef.current = L.map(mapContainerRef.current).setView([loc.lat, loc.lng], 15);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '© OpenStreetMap contributors'
        }).addTo(mapRef.current);

        const motorIcon = L.divIcon({
          html: '<div class="bg-orange-600 w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-xl text-white"><i class="fa-solid fa-motorcycle"></i></div>',
          className: '',
          iconSize: [40, 40],
          iconAnchor: [20, 20]
        });

        markerRef.current = L.marker([loc.lat, loc.lng], { icon: motorIcon }).addTo(mapRef.current);
      } else {
        markerRef.current.setLatLng([loc.lat, loc.lng]);
        mapRef.current.panTo([loc.lat, loc.lng]);
      }
    }
  }, [activeOrder?.status, activeOrder?.deliveryLocation]);

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDish) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      customerName: formData.name,
      address: formData.address,
      phone: formData.phone,
      items: [{
        dishId: selectedDish.id,
        name: selectedDish.name,
        quantity: 1,
        price: selectedDish.price
