import React, { useState, useEffect, useRef } from 'react';
import { StorageService } from '../services/storageService';
import { Dish, Order, OrderStatus, LatLng, PaymentMethod } from '../types';

declare const L: any; // Leaflet global

const CustomerView: React.FC = () => {
  const [menu, setMenu] = useState<Dish[]>([]);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);
  const [formData, setFormData] = useState({ name: '', address: '', phone: '', paymentMethod: PaymentMethod.CASH_ON_DELIVERY });
  const [isOrdering, setIsOrdering] = useState(false);
  const [selectedDish, setSelectedDish] = useState<Dish | null>(null);

  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);

  useEffect(() => {
    setMenu(StorageService.getMenu());
    const orders = StorageService.getOrders();
    const lastOrder = orders.find(o => o.status !== OrderStatus.DELIVERED && o.status !== OrderStatus.CANCELLED);
    if (lastOrder) setActiveOrder(lastOrder);

    const interval = setInterval(() => {
      const updatedOrders = StorageService.getOrders();
      const currentOrderId = activeOrder?.id || lastOrder?.id;
      if (currentOrderId) {
        const refreshed = updatedOrders.find(o => o.id === currentOrderId);
        if (refreshed && refreshed.status !== OrderStatus.CANCELLED) {
          setActiveOrder(refreshed);
        } else if (refreshed && refreshed.status === OrderStatus.CANCELLED) {
          setActiveOrder(null);
        }
      }
    }, 3000);

    return () => clearInterval(interval);
  }, [activeOrder?.id]);

  // Handle Map Logic
  useEffect(() => {
    if (activeOrder?.status === OrderStatus.IN_TRANSIT && activeOrder.deliveryLocation && mapContainerRef.current) {
      const loc = activeOrder.deliveryLocation;

      if (!mapRef.current) {
        mapRef.current = L.map(mapContainerRef.current).setView([loc.lat, loc.lng], 15);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '© OpenStreetMap contributors'
        }).addTo(mapRef.current);

        const motorIcon = L.divIcon({
          html: '<div class="bg-orange-600 w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-xl text-white"><i class="fa-solid fa-motorcycle"></i></div>',
          className: '',
          iconSize: [40, 40],
          iconAnchor: [20, 20]
        });

        markerRef.current = L.marker([loc.lat, loc.lng], { icon: motorIcon }).addTo(mapRef.current);
      } else {
        markerRef.current.setLatLng([loc.lat, loc.lng]);
        mapRef.current.panTo([loc.lat, loc.lng]);
      }
    }
  }, [activeOrder?.status, activeOrder?.deliveryLocation]);

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDish) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      customerName: formData.name,
      address: formData.address,
      phone: formData.phone,
      paymentMethod: formData.paymentMethod,
      items: [{
        dishId: selectedDish.id,
        name: selectedDish.name,
        quantity: 1,
        price: selectedDish.price
      }],
      total: selectedDish.price,
      status: OrderStatus.PENDING,
      createdAt: Date.now()
    };

    StorageService.saveOrder(newOrder);
    setActiveOrder(newOrder);
    setIsOrdering(false);
    setSelectedDish(null);
  };

  const handleCancelOrder = () => {
    if (!activeOrder) return;

    const confirmCancel = window.confirm('¿Estás seguro de que deseas cancelar tu orden? Esta acción no se puede deshacer.');
    if (confirmCancel) {
      StorageService.updateOrderStatus(activeOrder.id, OrderStatus.CANCELLED);
      setActiveOrder(null);
      alert('Tu orden ha sido cancelada.');
    }
  };

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-yellow-100 text-yellow-800';
      case OrderStatus.PREPARING: return 'bg-blue-100 text-blue-800';
      case OrderStatus.IN_TRANSIT: return 'bg-orange-100 text-orange-800';
      case OrderStatus.DELIVERED: return 'bg-green-100 text-green-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusLabel = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'Confirmando...';
      case OrderStatus.PREPARING: return 'En el fogón 🍳';
      case OrderStatus.IN_TRANSIT: return 'En camino 🛵';
      case OrderStatus.DELIVERED: return '¡Entregado! 🍛';
      default: return status;
    }
  };

  if (activeOrder && activeOrder.status !== OrderStatus.DELIVERED && activeOrder.status !== OrderStatus.CANCELLED) {
    return (
      <div className="max-w-4xl mx-auto py-8 px-4">
        <h2 className="text-3xl font-black mb-6 text-center text-orange-700 tracking-tight uppercase">Sigue Tu Sabor Live</h2>

        <div className="grid grid-cols-1 md:grid-cols-5 gap-6">
          <div className="md:col-span-2 space-y-6">
            <div className="bg-white rounded-3xl shadow-xl p-6 border border-orange-100 h-full flex flex-col">
              <div className="mb-6 flex justify-between items-start">
                <div>
                  <p className="text-xs text-stone-400 font-bold uppercase tracking-widest mb-1">Estado del Pedido</p>
                  <div className={`px-4 py-2 rounded-2xl font-bold inline-block text-sm ${getStatusColor(activeOrder.status)}`}>
                    {getStatusLabel(activeOrder.status)}
                  </div>
                </div>
                {activeOrder.status === OrderStatus.PENDING && (
                  <button 
                    onClick={handleCancelOrder}
                    className="text-red-500 hover:text-red-700 text-xs font-bold uppercase tracking-widest bg-red-50 px-3 py-1 rounded-lg transition"
                  >
                    <i className="fa-solid fa-trash-can mr-1"></i> Cancelar
                  </button>
                )}
              </div>

              <div className="space-y-6 relative before:content-[''] before:absolute before:left-[15px] before:top-2 before:bottom-2 before:w-0.5 before:bg-orange-100">
                <div className="flex items-start relative z-10">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${activeOrder.status !== OrderStatus.CANCELLED ? 'bg-orange-600' : 'bg-stone-300'}`}>
