                    </div>
                    <div className="text-left">
                      <p className="font-bold text-sm">Pago anticipado</p>
                      <p className="text-xs text-stone-500">Tarjeta o transferencia bancaria</p>
                    </div>
                  </button>
                </div>
              </div>

              <div className="pt-4">
                <button type="submit" className="w-full bg-orange-600 text-white py-5 rounded-2xl font-black hover:bg-orange-700 shadow-xl transition-all active:scale-95 uppercase tracking-widest">
                  Confirmar Pedido RD$ {selectedDish.price}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-bounce-slow {
          animation: bounce-slow 3s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

