                <div>
                  <p className="text-xs text-stone-400 font-bold uppercase tracking-widest mb-1">Estado del Pedido</p>
                  <div className={`px-4 py-2 rounded-2xl font-bold inline-block text-sm ${getStatusColor(activeOrder.status)}`}>
                    {getStatusLabel(activeOrder.status)}
                  </div>
                </div>
                {activeOrder.status === OrderStatus.PENDING && (
                  <button 
                    onClick={handleCancelOrder}
                    className="text-red-500 hover:text-red-700 text-xs font-bold uppercase tracking-widest bg-red-50 px-3 py-1 rounded-lg transition"
                  >
                    <i className="fa-solid fa-trash-can mr-1"></i> Cancelar
                  </button>
                )}
              </div>

              <div className="space-y-6 relative before:content-[''] before:absolute before:left-[15px] before:top-2 before:bottom-2 before:w-0.5 before:bg-orange-100">
                <div className="flex items-start relative z-10">
                  <div className="w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm bg-orange-600">
                    <i className="fa-solid fa-receipt text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">Recibido</p>
                  </div>
                </div>
                <div className="flex items-start relative z-10">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.PREPARING, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                    <i className="fa-solid fa-fire-burner text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">Preparando</p>
                  </div>
