                    <i className="fa-solid fa-motorcycle text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">En Camino</p>
                  </div>
                </div>
              </div>

              <div className="mt-8 pt-6 border-t border-stone-50">
                <p className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Detalles del Pago</p>
                <p className="text-sm font-bold text-stone-800">
                  {activeOrder.paymentMethod === PaymentMethod.CASH_ON_DELIVERY ? 'Efectivo contra entrega' : 'Pago anticipado (Completado)'}
                </p>
                <p className="text-sm font-black text-orange-600 mt-1">Total: RD$ {activeOrder.total}</p>
              </div>

              <div className="mt-4 pt-6 border-t border-stone-50 mb-auto">
                <p className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Destino</p>
                <p className="text-sm font-medium text-stone-800">{activeOrder.address}</p>
                {activeOrder.notes && (
                   <p className="text-xs text-stone-600 mt-2 bg-stone-50 p-2 rounded-lg border border-stone-100 italic">
                     <span className="font-bold not-italic">Nota:</span> {activeOrder.notes}
                   </p>
                )}
              </div>

              <div className="mt-8 space-y-3">
                <button 
                  onClick={() => setViewMode('MENU')}
                  className="w-full bg-stone-100 text-stone-500 py-3 rounded-2xl text-xs font-bold hover:bg-stone-200 transition"
                >
                  Volver al Menú
                </button>
              </div>
            </div>
          </div>

          <div className="md:col-span-3">
            <div className="bg-stone-200 rounded-3xl h-[400px] md:h-full relative overflow-hidden shadow-xl border-4 border-white">
              {activeOrder.status === OrderStatus.IN_TRANSIT ? (
                <div ref={mapContainerRef} className="w-full h-full"></div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-center p-8">
                  <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-4 shadow-sm">
                    {activeOrder.status === OrderStatus.PREPARING ? (
                      <i className="fa-solid fa-utensils text-3xl text-orange-400 animate-bounce"></i>
                    ) : (
                      <i className="fa-solid fa-clock text-3xl text-yellow-400 animate-spin-slow"></i>
                    )}
                  </div>
                  <h4 className="text-lg font-bold text-stone-700">El mapa se activará cuando salga el delivery</h4>
                  <p className="text-sm text-stone-500 mt-2">Estamos poniendo todo el sazón para que llegue perfecto.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // History View
  if (viewMode === 'HISTORY') {
    return (
      <div className="max-w-4xl mx-auto py-8 px-4">
        <div className="flex items-center justify-between mb-8">
           <button onClick={() => setViewMode('MENU')} className="bg-stone-100 text-stone-500 px-4 py-2 rounded-xl text-sm font-bold hover:bg-stone-200 transition flex items-center">
             <i className="fa-solid fa-arrow-left mr-2"></i> Volver al Menú
           </button>
           <h2 className="text-2xl font-black text-stone-800 uppercase tracking-tight">Mi Historial</h2>
        </div>

        {history.length === 0 ? (
          <div className="bg-white rounded-3xl p-16 text-center border-2 border-dashed border-stone-200 shadow-sm">
            <div className="w-20 h-20 bg-stone-50 rounded-full flex items-center justify-center mx-auto mb-4">
               <i className="fa-solid fa-history text-3xl text-stone-200"></i>
            </div>
            <p className="text-stone-400 font-bold">No tienes pedidos anteriores aún.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {history.map(order => (
              <div key={order.id} className="bg-white rounded-2xl p-6 shadow-sm border border-stone-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
