                      }`}>
                        {order.status === OrderStatus.PREPARING ? 'LISTO PARA RECOGER' : 'EN RUTA'}
                      </span>
                    </div>

                    <div>
                      <h3 className="text-2xl font-black text-stone-800">{order.customerName}</h3>
                      <p className="text-stone-600 font-medium mt-1 text-lg leading-snug">
                        {order.address}
                      </p>
                      {order.notes && (
