                      >
                        <i className="fa-solid fa-box-open mr-3"></i>
                        Recoger Orden
                      </button>
                    )}
                    {order.status === OrderStatus.IN_TRANSIT && (
                      <button 
                        onClick={() => updateStatus(order.id, OrderStatus.DELIVERED)}
