                      >
                        <i className="fa-solid fa-circle-check mr-3"></i>
                        Confirmar Entrega
                      </button>
                    )}

                    <div className="grid grid-cols-2 gap-3">
                      <a 
                        href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(order.address)}`}
