export const StorageService = {
  getOrders: (): Order[] => {
    const data = localStorage.getItem(KEYS.ORDERS);
    return data ? JSON.parse(data) : [];
  },

  saveOrder: (order: Order) => {
    const orders = StorageService.getOrders();
    orders.push(order);
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(orders));
  },

  updateOrderStatus: (orderId: string, status: OrderStatus) => {
    const orders = StorageService.getOrders();
    const updated = orders.map(o => o.id === orderId ? { ...o, status } : o);
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(updated));
  },

  assignDelivery: (orderId: string, deliveryId: string) => {
    const orders = StorageService.getOrders();
    const updated = orders.map(o => o.id === orderId ? { 
      ...o, 
      deliveryAssignedTo: deliveryId,
      status: OrderStatus.PREPARING 
    } : o);
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(updated));
  },

  updateDeliveryLocation: (deliveryId: string, location: LatLng) => {
    const locations = JSON.parse(localStorage.getItem(KEYS.LOCATIONS) || '{}');
    locations[deliveryId] = location;
    localStorage.setItem(KEYS.LOCATIONS, JSON.stringify(locations));

    // Also update order if it's in transit to help client tracking
    const orders = StorageService.getOrders();
    const updatedOrders = orders.map(o => 
      (o.deliveryAssignedTo === deliveryId && o.status === OrderStatus.IN_TRANSIT) 
      ? { ...o, deliveryLocation: location } 
      : o
    );
    localStorage.setItem(KEYS.ORDERS, JSON.stringify(updatedOrders));
  },

  getDeliveryLocation: (deliveryId: string): LatLng | null => {
    const locations = JSON.parse(localStorage.getItem(KEYS.LOCATIONS) || '{}');
    return locations[deliveryId] || null;
  },

  getMenu: (): Dish[] => {
    const data = localStorage.getItem(KEYS.MENU);
    // Ensure all items have a category
    const menuItems: Dish[] = data ? JSON.parse(data) : DEFAULT_MENU;
    return menuItems.map(item => ({ ...item, category: item.category || 'Platos' }));
  },

  saveMenu: (menu: Dish[]) => {
    localStorage.setItem(KEYS.MENU, JSON.stringify(menu));
  },

  getDeliveryPeople: (): DeliveryPerson[] => {
    const data = localStorage.getItem(KEYS.DELIVERY_PEOPLE);
    return data ? JSON.parse(data) : DEFAULT_DELIVERY;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { StorageService } from '../services/storageService';
import { Dish, Order, OrderStatus, LatLng, PaymentMethod } from '../types';

declare const L: any; // Leaflet global

const CustomerView: React.FC = () => {
  const [menu, setMenu] = useState<Dish[]>([]);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);
  const [history, setHistory] = useState<Order[]>([]);
  const [viewMode, setViewMode] = useState<'MENU' | 'TRACKING' | 'HISTORY'>('MENU');
  const [activeCategory, setActiveCategory] = useState<string>('Platos');
  const [formData, setFormData] = useState({ 
    name: '', 
    address: '', 
    phone: '', 
    notes: '',
    paymentMethod: PaymentMethod.CASH_ON_DELIVERY 
  });
  const [isOrdering, setIsOrdering] = useState(false);
  const [selectedDish, setSelectedDish] = useState<Dish | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);

  // Categories available in the app
  const categories = ['Platos', 'Bebidas', 'Postres'];

  // Initial load: check for existing active orders and load menu
  useEffect(() => {
    setMenu(StorageService.getMenu());
    const orders = StorageService.getOrders();
    const lastOrder = orders.find(o => o.status !== OrderStatus.DELIVERED && o.status !== OrderStatus.CANCELLED);
    if (lastOrder) {
      setActiveOrder(lastOrder);
      setViewMode('TRACKING');
    }
    setHistory(orders.filter(o => o.status === OrderStatus.DELIVERED || o.status === OrderStatus.CANCELLED).sort((a, b) => b.createdAt - a.createdAt));
  }, []);

  // Sync active order status in background
  useEffect(() => {
    const interval = setInterval(() => {
      const allOrders = StorageService.getOrders();

      // Update history list
      setHistory(allOrders.filter(o => o.status === OrderStatus.DELIVERED || o.status === OrderStatus.CANCELLED).sort((a, b) => b.createdAt - a.createdAt));

      if (activeOrder) {
        const refreshed = allOrders.find(o => o.id === activeOrder.id);
        if (refreshed) {
          if (refreshed.status === OrderStatus.CANCELLED || refreshed.status === OrderStatus.DELIVERED) {
            setActiveOrder(null);
            // If they were tracking, maybe they want to see the history now
            if (viewMode === 'TRACKING') {
              setViewMode('HISTORY');
            }
          } else {
            setActiveOrder(refreshed);
          }
        }
      }
    }, 3000);

    return () => clearInterval(interval);
  }, [activeOrder?.id, viewMode]);

  // Handle Map Logic for Tracking
  useEffect(() => {
    if (viewMode === 'TRACKING' && activeOrder?.status === OrderStatus.IN_TRANSIT && activeOrder.deliveryLocation && mapContainerRef.current) {
      const loc = activeOrder.deliveryLocation;

      if (!mapRef.current) {
        mapRef.current = L.map(mapContainerRef.current).setView([loc.lat, loc.lng], 15);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '© OpenStreetMap contributors'
        }).addTo(mapRef.current);

        const motorIcon = L.divIcon({
          html: '<div class="bg-orange-600 w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-xl text-white"><i class="fa-solid fa-motorcycle"></i></div>',
          className: '',
          iconSize: [40, 40],
          iconAnchor: [20, 20]
        });

        markerRef.current = L.marker([loc.lat, loc.lng], { icon: motorIcon }).addTo(mapRef.current);
      } else {
        markerRef.current.setLatLng([loc.lat, loc.lng]);
        mapRef.current.panTo([loc.lat, loc.lng]);
      }
    }
  }, [viewMode, activeOrder?.status, activeOrder?.deliveryLocation]);

  const handleGetLocation = () => {
    if (!navigator.geolocation) {
      alert("Tu navegador no soporta geolocalización.");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const mockAddress = `Ubicación GPS: ${latitude.toFixed(6)}, ${longitude.toFixed(6)}`;
        setFormData(prev => ({ ...prev, address: mockAddress }));
        setIsLocating(false);
      },
      (error) => {
        console.error(error);
        alert("No pudimos obtener tu ubicación. Por favor, escríbela manualmente.");
        setIsLocating(false);
      },
      { enableHighAccuracy: true }
    );
  };

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDish) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      customerName: formData.name,
      address: formData.address,
      phone: formData.phone,
      notes: formData.notes,
      paymentMethod: formData.paymentMethod,
      items: [{
        dishId: selectedDish.id,
        name: selectedDish.name,
        quantity: 1,
        price: selectedDish.price
      }],
      total: selectedDish.price,
      status: OrderStatus.PENDING,
      createdAt: Date.now()
    };

    StorageService.saveOrder(newOrder);
    setActiveOrder(newOrder);
    setViewMode('TRACKING');
    setIsOrdering(false);
    setSelectedDish(null);
  };

  const handleCancelOrder = () => {
    if (!activeOrder) return;

    const confirmCancel = window.confirm('¿Estás seguro de que deseas cancelar tu orden? Esta acción no se puede deshacer.');
    if (confirmCancel) {
      StorageService.updateOrderStatus(activeOrder.id, OrderStatus.CANCELLED);
      setActiveOrder(null);
      setViewMode('MENU');
      alert('Tu orden ha sido cancelada.');
    }
  };

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-yellow-100 text-yellow-800';
      case OrderStatus.PREPARING: return 'bg-blue-100 text-blue-800';
      case OrderStatus.IN_TRANSIT: return 'bg-orange-100 text-orange-800';
      case OrderStatus.DELIVERED: return 'bg-green-100 text-green-800';
      case OrderStatus.CANCELLED: return 'bg-stone-100 text-stone-500';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusLabel = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'Confirmando...';
      case OrderStatus.PREPARING: return 'En el fogón 🍳';
      case OrderStatus.IN_TRANSIT: return 'En camino 🛵';
      case OrderStatus.DELIVERED: return '¡Entregado! 🍛';
      case OrderStatus.CANCELLED: return 'Cancelado ❌';
      default: return status;
    }
  };

  const filteredMenu = menu.filter(d => d.available && d.category === activeCategory);

  // Tracking View
  if (viewMode === 'TRACKING' && activeOrder) {
    return (
      <div className="max-w-4xl mx-auto py-8 px-4">
        <h2 className="text-3xl font-black mb-6 text-center text-orange-700 tracking-tight uppercase">Sigue Tu Sabor Live</h2>

        <div className="grid grid-cols-1 md:grid-cols-5 gap-6">
          <div className="md:col-span-2 space-y-6">
            <div className="bg-white rounded-3xl shadow-xl p-6 border border-orange-100 h-full flex flex-col">
              <div className="mb-6 flex justify-between items-start">
                <div>
                  <p className="text-xs text-stone-400 font-bold uppercase tracking-widest mb-1">Estado del Pedido</p>
                  <div className={`px-4 py-2 rounded-2xl font-bold inline-block text-sm ${getStatusColor(activeOrder.status)}`}>
                    {getStatusLabel(activeOrder.status)}
                  </div>
                </div>
                {activeOrder.status === OrderStatus.PENDING && (
                  <button 
                    onClick={handleCancelOrder}
                    className="text-red-500 hover:text-red-700 text-xs font-bold uppercase tracking-widest bg-red-50 px-3 py-1 rounded-lg transition"
                  >
                    <i className="fa-solid fa-trash-can mr-1"></i> Cancelar
                  </button>
                )}
              </div>

              <div className="space-y-6 relative before:content-[''] before:absolute before:left-[15px] before:top-2 before:bottom-2 before:w-0.5 before:bg-orange-100">
                <div className="flex items-start relative z-10">
                  <div className="w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm bg-orange-600">
                    <i className="fa-solid fa-receipt text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">Recibido</p>
                  </div>
                </div>
                <div className="flex items-start relative z-10">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.PREPARING, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                    <i className="fa-solid fa-fire-burner text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">Preparando</p>
                  </div>
                </div>
                <div className="flex items-start relative z-10">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                    <i className="fa-solid fa-motorcycle text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">En Camino</p>
                  </div>
                </div>
              </div>

              <div className="mt-8 pt-6 border-t border-stone-50">
                <p className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Detalles del Pago</p>
                <p className="text-sm font-bold text-stone-800">
                  {activeOrder.paymentMethod === PaymentMethod.CASH_ON_DELIVERY ? 'Efectivo contra entrega' : 'Pago anticipado (Completado)'}
                </p>
                <p className="text-sm font-black text-orange-600 mt-1">Total: RD$ {activeOrder.total}</p>
