                    <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center mr-3 ${formData.paymentMethod === PaymentMethod.CASH_ON_DELIVERY ? 'border-orange-600 bg-orange-600' : 'border-stone-200'}`}>
                      {formData.paymentMethod === PaymentMethod.CASH_ON_DELIVERY && <i className="fa-solid fa-check text-white text-[10px]"></i>}
                    </div>
                    <div className="text-left">
                      <p className="font-bold text-sm">Pagar contra entrega</p>
                      <p className="text-xs text-stone-500">Paga en efectivo al recibir tu plato</p>
                    </div>
                  </button>
                  <button 
                    type="button"
                    onClick={() => setFormData({...formData, paymentMethod: PaymentMethod.PREPAID})}
                    className={`flex items-center p-4 rounded-2xl border-2 transition ${formData.paymentMethod === PaymentMethod.PREPAID ? 'border-orange-600 bg-orange-50' : 'border-stone-100 bg-white hover:border-orange-200'}`}
                  >
                    <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center mr-3 ${formData.paymentMethod === PaymentMethod.PREPAID ? 'border-orange-600 bg-orange-600' : 'border-stone-200'}`}>
                      {formData.paymentMethod === PaymentMethod.PREPAID && <i className="fa-solid fa-check text-white text-[10px]"></i>}
                    </div>
                    <div className="text-left">
                      <p className="font-bold text-sm">Pago anticipado</p>
                      <p className="text-xs text-stone-500">Tarjeta o transferencia bancaria</p>
                    </div>
                  </button>
                </div>
              </div>

              <div className="pt-4">
                <button type="submit" className="w-full bg-orange-600 text-white py-5 rounded-2xl font-black hover:bg-orange-700 shadow-xl transition-all active:scale-95 uppercase tracking-widest">
                  Confirmar Pedido RD$ {selectedDish.price}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <style>{`
        @keyframes bounce-slow {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        .animate-bounce-slow {
          animation: bounce-slow 3s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

