                        <button 
                          onClick={() => handlePrint(order)}
                          className="w-full text-[10px] bg-stone-100 text-stone-600 py-1.5 rounded-lg font-bold hover:bg-stone-200 transition flex items-center justify-center"
                        >
                          <i className="fa-solid fa-print mr-1"></i> Imprimir Ticket
                        </button>

                        {order.status === OrderStatus.PENDING ? (
                          <select 
                            className="w-full text-[10px] bg-white border border-stone-200 rounded-lg p-1.5 outline-none focus:ring-2 focus:ring-orange-500 font-bold"
                            onChange={(e) => handleAssign(order.id, e.target.value)}
                            defaultValue=""
                          >
                            <option value="" disabled>Asignar...</option>
                            {deliveryPeople.map(d => (
                              <option key={d.id} value={d.id}>{d.name}</option>
                            ))}
                          </select>
                        ) : (
                          <p className="text-[10px] text-stone-400 italic text-center">
                            {deliveryPeople.find(d => d.id === order.deliveryAssignedTo)?.name || 'Asignado'}
                          </p>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
                {orders.length === 0 && (
                  <tr>
                    <td colSpan={6} className="py-12 text-center text-stone-400 italic">
                      No hay órdenes pendientes hoy.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </section>

      <style>{`
        @media print {
          body * {
            visibility: hidden;
          }
          #printable-ticket, #printable-ticket * {
            visibility: visible;
          }
          #printable-ticket {
            position: absolute;
            left: 0;
            top: 0;
            display: block !important;
          }
        }
      `}</style>
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect, useRef } from 'react';
import { StorageService } from '../services/storageService';
import { Dish, Order, OrderStatus, LatLng, PaymentMethod } from '../types';

declare const L: any; // Leaflet global

const CustomerView: React.FC = () => {
  const [menu, setMenu] = useState<Dish[]>([]);
  const [activeOrder, setActiveOrder] = useState<Order | null>(null);
  const [history, setHistory] = useState<Order[]>([]);
  const [viewMode, setViewMode] = useState<'MENU' | 'TRACKING' | 'HISTORY'>('MENU');
  const [activeCategory, setActiveCategory] = useState<string>('Platos');
  const [formData, setFormData] = useState({ 
    name: '', 
    address: '', 
    phone: '', 
    notes: '',
    paymentMethod: PaymentMethod.CASH_ON_DELIVERY 
  });
  const [isOrdering, setIsOrdering] = useState(false);
  const [selectedDish, setSelectedDish] = useState<Dish | null>(null);
  const [isLocating, setIsLocating] = useState(false);

  const mapContainerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<any>(null);
  const markerRef = useRef<any>(null);

  // Categories available in the app
  const categories = ['Platos', 'Bebidas', 'Postres'];

  // Initial load: check for existing active orders and load menu
  useEffect(() => {
    setMenu(StorageService.getMenu());
    const orders = StorageService.getOrders();
    const lastOrder = orders.find(o => o.status !== OrderStatus.DELIVERED && o.status !== OrderStatus.CANCELLED);
    if (lastOrder) {
      setActiveOrder(lastOrder);
      setViewMode('TRACKING');
    }
    setHistory(orders.filter(o => o.status === OrderStatus.DELIVERED || o.status === OrderStatus.CANCELLED).sort((a, b) => b.createdAt - a.createdAt));
  }, []);

  // Sync active order status in background
  useEffect(() => {
    const interval = setInterval(() => {
      const allOrders = StorageService.getOrders();

      // Update history list
      setHistory(allOrders.filter(o => o.status === OrderStatus.DELIVERED || o.status === OrderStatus.CANCELLED).sort((a, b) => b.createdAt - a.createdAt));

      if (activeOrder) {
        const refreshed = allOrders.find(o => o.id === activeOrder.id);
        if (refreshed) {
          if (refreshed.status === OrderStatus.CANCELLED || refreshed.status === OrderStatus.DELIVERED) {
            setActiveOrder(null);
            // If they were tracking, maybe they want to see the history now
            if (viewMode === 'TRACKING') {
              setViewMode('HISTORY');
            }
          } else {
            setActiveOrder(refreshed);
          }
        }
      }
    }, 3000);

    return () => clearInterval(interval);
  }, [activeOrder?.id, viewMode]);

  // Handle Map Logic for Tracking
  useEffect(() => {
    if (viewMode === 'TRACKING' && activeOrder?.status === OrderStatus.IN_TRANSIT && activeOrder.deliveryLocation && mapContainerRef.current) {
      const loc = activeOrder.deliveryLocation;

      if (!mapRef.current) {
        mapRef.current = L.map(mapContainerRef.current).setView([loc.lat, loc.lng], 15);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '© OpenStreetMap contributors'
        }).addTo(mapRef.current);

        const motorIcon = L.divIcon({
          html: '<div class="bg-orange-600 w-10 h-10 rounded-full flex items-center justify-center border-4 border-white shadow-xl text-white"><i class="fa-solid fa-motorcycle"></i></div>',
          className: '',
          iconSize: [40, 40],
          iconAnchor: [20, 20]
        });

        markerRef.current = L.marker([loc.lat, loc.lng], { icon: motorIcon }).addTo(mapRef.current);
      } else {
        markerRef.current.setLatLng([loc.lat, loc.lng]);
        mapRef.current.panTo([loc.lat, loc.lng]);
      }
    }
  }, [viewMode, activeOrder?.status, activeOrder?.deliveryLocation]);

  const handleGetLocation = () => {
    if (!navigator.geolocation) {
      alert("Tu navegador no soporta geolocalización.");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;
        const mockAddress = `Ubicación GPS: ${latitude.toFixed(6)}, ${longitude.toFixed(6)}`;
        setFormData(prev => ({ ...prev, address: mockAddress }));
        setIsLocating(false);
      },
      (error) => {
        console.error(error);
        alert("No pudimos obtener tu ubicación. Por favor, escríbela manualmente.");
        setIsLocating(false);
      },
      { enableHighAccuracy: true }
    );
  };

  const handleOrder = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDish) return;

    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      customerName: formData.name,
      address: formData.address,
      phone: formData.phone,
      notes: formData.notes,
      paymentMethod: formData.paymentMethod,
      items: [{
        dishId: selectedDish.id,
        name: selectedDish.name,
        quantity: 1,
        price: selectedDish.price
      }],
      total: selectedDish.price,
      status: OrderStatus.PENDING,
      createdAt: Date.now()
    };

    StorageService.saveOrder(newOrder);
    setActiveOrder(newOrder);
    setViewMode('TRACKING');
    setIsOrdering(false);
    setSelectedDish(null);
  };

  const handleCancelOrder = () => {
    if (!activeOrder) return;

    const confirmCancel = window.confirm('¿Estás seguro de que deseas cancelar tu orden? Esta acción no se puede deshacer.');
    if (confirmCancel) {
      StorageService.updateOrderStatus(activeOrder.id, OrderStatus.CANCELLED);
      setActiveOrder(null);
      setViewMode('MENU');
      alert('Tu orden ha sido cancelada.');
    }
  };

  const getStatusColor = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'bg-yellow-100 text-yellow-800';
      case OrderStatus.PREPARING: return 'bg-blue-100 text-blue-800';
      case OrderStatus.IN_TRANSIT: return 'bg-orange-100 text-orange-800';
      case OrderStatus.DELIVERED: return 'bg-green-100 text-green-800';
      case OrderStatus.CANCELLED: return 'bg-stone-100 text-stone-500';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusLabel = (status: OrderStatus) => {
    switch (status) {
      case OrderStatus.PENDING: return 'Confirmando...';
      case OrderStatus.PREPARING: return 'En el fogón 🍳';
      case OrderStatus.IN_TRANSIT: return 'En camino 🛵';
      case OrderStatus.DELIVERED: return '¡Entregado! 🍛';
      case OrderStatus.CANCELLED: return 'Cancelado ❌';
      default: return status;
    }
  };

  const filteredMenu = menu.filter(d => d.available && d.category === activeCategory);

  // Tracking View
  if (viewMode === 'TRACKING' && activeOrder) {
    return (
      <div className="max-w-4xl mx-auto py-8 px-4">
        <h2 className="text-3xl font-black mb-6 text-center text-orange-700 tracking-tight uppercase">Sigue Tu Sabor Live</h2>

        <div className="grid grid-cols-1 md:grid-cols-5 gap-6">
          <div className="md:col-span-2 space-y-6">
            <div className="bg-white rounded-3xl shadow-xl p-6 border border-orange-100 h-full flex flex-col">
              <div className="mb-6 flex justify-between items-start">
                <div>
                  <p className="text-xs text-stone-400 font-bold uppercase tracking-widest mb-1">Estado del Pedido</p>
                  <div className={`px-4 py-2 rounded-2xl font-bold inline-block text-sm ${getStatusColor(activeOrder.status)}`}>
                    {getStatusLabel(activeOrder.status)}
                  </div>
                </div>
                {activeOrder.status === OrderStatus.PENDING && (
                  <button 
                    onClick={handleCancelOrder}
                    className="text-red-500 hover:text-red-700 text-xs font-bold uppercase tracking-widest bg-red-50 px-3 py-1 rounded-lg transition"
                  >
                    <i className="fa-solid fa-trash-can mr-1"></i> Cancelar
                  </button>
                )}
              </div>

              <div className="space-y-6 relative before:content-[''] before:absolute before:left-[15px] before:top-2 before:bottom-2 before:w-0.5 before:bg-orange-100">
                <div className="flex items-start relative z-10">
                  <div className="w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm bg-orange-600">
                    <i className="fa-solid fa-receipt text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">Recibido</p>
                  </div>
                </div>
                <div className="flex items-start relative z-10">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.PREPARING, OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                    <i className="fa-solid fa-fire-burner text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">Preparando</p>
                  </div>
                </div>
                <div className="flex items-start relative z-10">
                  <div className={`w-8 h-8 rounded-full flex items-center justify-center border-4 border-white shadow-sm ${[OrderStatus.IN_TRANSIT, OrderStatus.DELIVERED].includes(activeOrder.status) ? 'bg-orange-600' : 'bg-stone-200'}`}>
                    <i className="fa-solid fa-motorcycle text-white text-[10px]"></i>
                  </div>
                  <div className="ml-3">
                    <p className="font-bold text-sm">En Camino</p>
                  </div>
                </div>
              </div>

              <div className="mt-8 pt-6 border-t border-stone-50">
                <p className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Detalles del Pago</p>
                <p className="text-sm font-bold text-stone-800">
                  {activeOrder.paymentMethod === PaymentMethod.CASH_ON_DELIVERY ? 'Efectivo contra entrega' : 'Pago anticipado (Completado)'}
                </p>
                <p className="text-sm font-black text-orange-600 mt-1">Total: RD$ {activeOrder.total}</p>
              </div>

              <div className="mt-4 pt-6 border-t border-stone-50 mb-auto">
                <p className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-2">Destino</p>
                <p className="text-sm font-medium text-stone-800">{activeOrder.address}</p>
                {activeOrder.notes && (
                   <p className="text-xs text-stone-600 mt-2 bg-stone-50 p-2 rounded-lg border border-stone-100 italic">
                     <span className="font-bold not-italic">Nota:</span> {activeOrder.notes}
                   </p>
                )}
              </div>

              <div className="mt-8 space-y-3">
                <button 
                  onClick={() => setViewMode('MENU')}
                  className="w-full bg-stone-100 text-stone-500 py-3 rounded-2xl text-xs font-bold hover:bg-stone-200 transition"
                >
                  Volver al Menú
                </button>
              </div>
            </div>
          </div>

          <div className="md:col-span-3">
            <div className="bg-stone-200 rounded-3xl h-[400px] md:h-full relative overflow-hidden shadow-xl border-4 border-white">
              {activeOrder.status === OrderStatus.IN_TRANSIT ? (
                <div ref={mapContainerRef} className="w-full h-full"></div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-center p-8">
                  <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center mb-4 shadow-sm">
                    {activeOrder.status === OrderStatus.PREPARING ? (
                      <i className="fa-solid fa-utensils text-3xl text-orange-400 animate-bounce"></i>
                    ) : (
                      <i className="fa-solid fa-clock text-3xl text-yellow-400 animate-spin-slow"></i>
                    )}
                  </div>
                  <h4 className="text-lg font-bold text-stone-700">El mapa se activará cuando salga el delivery</h4>
                  <p className="text-sm text-stone-500 mt-2">Estamos poniendo todo el sazón para que llegue perfecto.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // History View
  if (viewMode === 'HISTORY') {
    return (
      <div className="max-w-4xl mx-auto py-8 px-4">
        <div className="flex items-center justify-between mb-8">
           <button onClick={() => setViewMode('MENU')} className="bg-stone-100 text-stone-500 px-4 py-2 rounded-xl text-sm font-bold hover:bg-stone-200 transition flex items-center">
             <i className="fa-solid fa-arrow-left mr-2"></i> Volver al Menú
           </button>
           <h2 className="text-2xl font-black text-stone-800 uppercase tracking-tight">Mi Historial</h2>
        </div>

        {history.length === 0 ? (
          <div className="bg-white rounded-3xl p-16 text-center border-2 border-dashed border-stone-200 shadow-sm">
            <div className="w-20 h-20 bg-stone-50 rounded-full flex items-center justify-center mx-auto mb-4">
               <i className="fa-solid fa-history text-3xl text-stone-200"></i>
            </div>
            <p className="text-stone-400 font-bold">No tienes pedidos anteriores aún.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {history.map(order => (
              <div key={order.id} className="bg-white rounded-2xl p-6 shadow-sm border border-stone-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                  <div className="flex items-center space-x-2 mb-1">
                    <span className="text-[10px] font-mono font-bold text-stone-400">#{order.id.toUpperCase()}</span>
                    <span className={`text-[10px] px-2 py-0.5 rounded-full font-bold uppercase ${getStatusColor(order.status)}`}>
                      {getStatusLabel(order.status)}
                    </span>
                  </div>
                  <h4 className="font-bold text-stone-800">{order.items.map(i => i.name).join(', ')}</h4>
                  <p className="text-xs text-stone-500">{new Date(order.createdAt).toLocaleDateString()} a las {new Date(order.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</p>
                </div>
                <div className="text-right">
                  <p className="text-lg font-black text-orange-600">RD$ {order.total}</p>
                  <p className="text-[10px] text-stone-400 uppercase font-black">{order.paymentMethod === PaymentMethod.CASH_ON_DELIVERY ? 'Efectivo' : 'Pagado'}</p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  // Menu View Content
  return (
    <div className="space-y-6 pb-12 relative">
      {/* Navigation Buttons */}
      <div className="fixed bottom-6 right-6 z-[90] flex flex-col items-end space-y-3">
        {activeOrder && (
          <button 
            onClick={() => setViewMode('TRACKING')}
            className="bg-orange-600 text-white px-6 py-4 rounded-full shadow-2xl font-black flex items-center space-x-3 hover:bg-orange-700 transition animate-bounce-slow"
          >
            <i className="fa-solid fa-motorcycle text-xl"></i>
            <span className="uppercase tracking-widest text-xs">Ver mi pedido en vivo</span>
          </button>
        )}
        <button 
          onClick={() => setViewMode('HISTORY')}
          className="bg-white text-stone-800 px-6 py-4 rounded-full shadow-2xl font-black flex items-center space-x-3 hover:bg-stone-50 transition border border-stone-100"
        >
          <i className="fa-solid fa-clock-rotate-left text-xl text-stone-400"></i>
          <span className="uppercase tracking-widest text-xs">Mi Historial</span>
        </button>
      </div>

      {/* Category Tabs */}
      <div className="flex justify-center space-x-2 md:space-x-4 sticky top-16 z-40 bg-stone-50/95 backdrop-blur-sm py-6 -mx-4 px-4 border-b border-stone-100 shadow-sm">
        {categories.map(cat => (
          <button 
            key={cat}
            onClick={() => setActiveCategory(cat)}
            className={`px-6 py-3 rounded-2xl text-xs md:text-sm font-black uppercase tracking-widest transition-all ${activeCategory === cat ? 'bg-orange-600 text-white shadow-lg' : 'bg-white text-stone-500 hover:bg-stone-100 shadow-sm border border-stone-100'}`}
          >
            {cat}
          </button>
        ))}
      </div>

      <section className="px-2">
        <div className="flex flex-col md:flex-row md:items-end justify-between mb-8 gap-4">
          <div>
            <h2 className="text-3xl font-black text-stone-800 uppercase tracking-tight">{activeCategory} del Día</h2>
            <p className="text-stone-500">Nuestros favoritos para deleitar tu paladar</p>
          </div>
          <div className="bg-white px-6 py-2 rounded-2xl shadow-sm border border-orange-100 flex items-center w-fit">
            <i className="fa-solid fa-calendar-day text-orange-600 mr-3"></i>
            <span className="font-bold text-stone-700">{new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}</span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredMenu.map(dish => (
            <div key={dish.id} className="bg-white rounded-3xl shadow-sm border border-stone-100 overflow-hidden group hover:shadow-2xl transition-all duration-500 hover:-translate-y-2">
              <div className="h-64 relative overflow-hidden">
                <img src={dish.imageUrl} alt={dish.name} className="w-full h-full object-cover group-hover:scale-110 transition duration-700" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition duration-500"></div>
                <div className="absolute top-4 right-4 bg-orange-600 text-white px-5 py-2 rounded-2xl font-black shadow-xl">
                  RD$ {dish.price}
                </div>
              </div>
              <div className="p-8">
                <h3 className="text-2xl font-bold mb-3 group-hover:text-orange-600 transition">{dish.name}</h3>
                <p className="text-stone-500 text-sm mb-8 leading-relaxed line-clamp-2">
                  {dish.description}
                </p>
                <button 
                  onClick={() => {
                    setSelectedDish(dish);
                    setIsOrdering(true);
                  }}
                  disabled={!!activeOrder}
                  className={`w-full py-4 rounded-2xl font-black shadow-lg transition-all active:scale-95 uppercase tracking-widest text-sm ${activeOrder ? 'bg-stone-200 text-stone-400 cursor-not-allowed' : 'bg-orange-600 text-white hover:bg-orange-700'}`}
                >
                  {activeOrder ? 'Ya tienes un pedido en curso' : `Pedir ${activeCategory === 'Platos' ? 'Plato' : activeCategory.slice(0, -1)}`}
                </button>
              </div>
            </div>
          ))}
          {filteredMenu.length === 0 && (
             <div className="col-span-full py-20 text-center bg-white rounded-3xl border-2 border-dashed border-stone-100">
               <p className="text-stone-400 font-bold italic">No hay {activeCategory.toLowerCase()} disponibles en este momento.</p>
             </div>
          )}
        </div>
      </section>

      {isOrdering && selectedDish && (
        <div className="fixed inset-0 bg-stone-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-lg p-10 transform animate-in fade-in zoom-in duration-300 border-4 border-orange-100 max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black uppercase tracking-tight">Confirma tu pedido</h3>
              <button onClick={() => setIsOrdering(false)} className="bg-stone-100 w-10 h-10 rounded-full flex items-center justify-center hover:bg-orange-100 hover:text-orange-600 transition">
                <i className="fa-solid fa-xmark"></i>
              </button>
            </div>

            <form onSubmit={handleOrder} className="space-y-5">
              <div>
                <label className="block text-xs font-black text-stone-400 uppercase tracking-widest mb-2">Nombre Completo</label>
                <input required type="text" className="w-full bg-stone-50 px-6 py-4 rounded-2xl border-2 border-transparent focus:border-orange-500 focus:bg-white outline-none transition" 
                  placeholder="Ej. Juan Pérez" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-black text-stone-400 uppercase tracking-widest mb-2 flex justify-between items-center">
                  Dirección de Envío
                  <button 
                    type="button" 
                    onClick={handleGetLocation}
                    className="text-[10px] text-orange-600 hover:underline flex items-center font-black"
                  >
                    {isLocating ? <i className="fa-solid fa-spinner animate-spin mr-1"></i> : <i className="fa-solid fa-location-crosshairs mr-1"></i>}
                    Usar GPS
                  </button>
                </label>
                <input required type="text" className="w-full bg-stone-50 px-6 py-4 rounded-2xl border-2 border-transparent focus:border-orange-500 focus:bg-white outline-none transition" 
                  placeholder="Calle, Sector, Edificio..." value={formData.address} onChange={(e) => setFormData({...formData, address: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-black text-stone-400 uppercase tracking-widest mb-2">Teléfono de Contacto</label>
                <input required type="tel" className="w-full bg-stone-50 px-6 py-4 rounded-2xl border-2 border-transparent focus:border-orange-500 focus:bg-white outline-none transition" 
                  placeholder="809-XXX-XXXX" value={formData.phone} onChange={(e) => setFormData({...formData, phone: e.target.value})}
                />
              </div>

              <div>
                <label className="block text-xs font-black text-stone-400 uppercase tracking-widest mb-2">Notas / Instrucciones especiales</label>
                <textarea 
                  className="w-full bg-stone-50 px-6 py-4 rounded-2xl border-2 border-transparent focus:border-orange-500 focus:bg-white outline-none transition resize-none h-24" 
                  placeholder="Ej. Sin cebolla, puerta roja, timbre malo..." 
                  value={formData.notes} 
                  onChange={(e) => setFormData({...formData, notes: e.target.value})}
                />
              </div>

              <div className="space-y-3">
                <label className="block text-xs font-black text-stone-400 uppercase tracking-widest">Método de Pago</label>
                <div className="grid grid-cols-1 gap-3">
                  <button 
                    type="button"
                    onClick={() => setFormData({...formData, paymentMethod: PaymentMethod.CASH_ON_DELIVERY})}
                    className={`flex items-center p-4 rounded-2xl border-2 transition ${formData.paymentMethod === PaymentMethod.CASH_ON_DELIVERY ? 'border-orange-600 bg-orange-50' : 'border-stone-100 bg-white hover:border-orange-200'}`}
                  >
