                                    <img src={dish.imageUrl} className="w-10 h-10 rounded-lg object-cover mr-3" />
                                    <div className="flex-grow">
                                        <p className="text-xs font-bold text-stone-800 group-hover:text-orange-600 transition">{dish.name}</p>
